SELECT c.*, ste.site_nm AS site_nm, cd_rwt.code_label AS writer_type_cd_nm FROM pd_review_comment c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_code cd_rwt ON cd_rwt.code_grp = 'REVIEW_WRITER_TYPE' AND cd_rwt.code_value = c.writer_type_cd
ORDER BY c.review_comment_id ASC ORDER BY c.review_comment_id DESC ORDER BY c.writer_nm ASC ORDER BY c.writer_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

