site_id = #{siteId}, review_id = #{reviewId}, parent_reply_id = #{parentReplyId}, writer_type_cd = #{writerTypeCd}, writer_id = #{writerId}, writer_nm = #{writerNm}, review_reply_content = #{reviewReplyContent}, reply_status_cd = #{replyStatusCd}, upd_by = #{updBy}, upd_date = #{updDate},
